+        }
+        if let Some(expected) = &self.expected_type {
+            parts.push(format!("expected={expected}"));
+        }
+        for (k, v) in &self.extra {
+            parts.push(format!("{k}={v}"));
+        }
+        parts.join(", ")
+    }
