+//! OpenAPI schema display component.
+//!
+//! Provides visual representation of OpenAPI specifications including
+//! endpoint tables, schema visualization, and documentation display.
+//!
+//! # Features
+//!
+//! - Endpoint summary table with method coloring
+//! - Schema type visualization (objects, arrays, enums)
+//! - Request/response body display
+//! - Authentication requirements display
+
+use crate::mode::OutputMode;
+use crate::themes::FastApiTheme;
+use std::collections::HashMap;
+use std::fmt::Write;
+
+const ANSI_RESET: &str = "\x1b[0m";
+const ANSI_BOLD: &str = "\x1b[1m";
+const ANSI_DIM: &str = "\x1b[2m";
+const ANSI_ITALIC: &str = "\x1b[3m";
+
+/// An OpenAPI endpoint for display.
+#[derive(Debug, Clone)]
+pub struct EndpointInfo {
+    /// HTTP method.
+    pub method: String,
+    /// Path pattern.
+    pub path: String,
+    /// Operation summary.
+    pub summary: Option<String>,
+    /// Operation description.
+    pub description: Option<String>,
+    /// Tags for grouping.
+    pub tags: Vec<String>,
+    /// Whether deprecated.
+    pub deprecated: bool,
+    /// Security requirements.
+    pub security: Vec<String>,
+    /// Operation ID.
+    pub operation_id: Option<String>,
+}
+
+impl EndpointInfo {
+    /// Create a new endpoint info.
+    #[must_use]
+    pub fn new(method: impl Into<String>, path: impl Into<String>) -> Self {
+        Self {
+            method: method.into(),
+            path: path.into(),
+            summary: None,
+            description: None,
+            tags: Vec::new(),
+            deprecated: false,
+            security: Vec::new(),
+            operation_id: None,
+        }
+    }
+
+    /// Set the summary.
+    #[must_use]
+    pub fn summary(mut self, summary: impl Into<String>) -> Self {
+        self.summary = Some(summary.into());
+        self
+    }
+
+    /// Set the description.
+    #[must_use]
+    pub fn description(mut self, description: impl Into<String>) -> Self {
+        self.description = Some(description.into());
+        self
+    }
+
+    /// Add a tag.
+    #[must_use]
+    pub fn tag(mut self, tag: impl Into<String>) -> Self {
+        self.tags.push(tag.into());
+        self
+    }
+
+    /// Mark as deprecated.
+    #[must_use]
+    pub fn deprecated(mut self, deprecated: bool) -> Self {
+        self.deprecated = deprecated;
+        self
+    }
+
+    /// Add a security requirement.
+    #[must_use]
+    pub fn security(mut self, security: impl Into<String>) -> Self {
+        self.security.push(security.into());
+        self
+    }
+
+    /// Set the operation ID.
+    #[must_use]
+    pub fn operation_id(mut self, id: impl Into<String>) -> Self {
+        self.operation_id = Some(id.into());
+        self
+    }
+}
+
+/// Schema type for display.
+#[derive(Debug, Clone)]
+pub enum SchemaType {
+    /// String type.
+    String {
+        /// Format (e.g., "email", "date-time").
+        format: Option<String>,
+        /// Enum values if constrained.
+        enum_values: Vec<String>,
+    },
+    /// Integer type.
+    Integer {
+        /// Format (e.g., "int32", "int64").
+        format: Option<String>,
+        /// Minimum value.
+        minimum: Option<i64>,
+        /// Maximum value.
+        maximum: Option<i64>,
+    },
+    /// Number type.
+    Number {
+        /// Format (e.g., "float", "double").
+        format: Option<String>,
+    },
+    /// Boolean type.
+    Boolean,
+    /// Array type.
+    Array {
+        /// Item schema.
+        items: Box<SchemaType>,
+    },
+    /// Object type.
+    Object {
+        /// Properties.
+        properties: Vec<PropertyInfo>,
+        /// Required property names.
+        required: Vec<String>,
+    },
+    /// Reference to another schema.
+    Ref {
+        /// Reference name.
+        name: String,
+    },
+    /// Any of (union type).
+    AnyOf {
+        /// Options.
+        options: Vec<SchemaType>,
+    },
+    /// Null type.
+    Null,
+}
+
+impl SchemaType {
+    /// Get a short type description.
+    #[must_use]
+    pub fn short_description(&self) -> String {
+        match self {
+            Self::String { format, enum_values } => {
+                if !enum_values.is_empty() {
+                    format!("enum[{}]", enum_values.len())
+                } else if let Some(fmt) = format {
+                    format!("string<{fmt}>")
+                } else {
+                    "string".to_string()
+                }
+            }
+            Self::Integer { format, .. } => {
+                if let Some(fmt) = format {
+                    format!("integer<{fmt}>")
+                } else {
+                    "integer".to_string()
+                }
+            }
+            Self::Number { format } => {
+                if let Some(fmt) = format {
+                    format!("number<{fmt}>")
+                } else {
+                    "number".to_string()
+                }
+            }
+            Self::Boolean => "boolean".to_string(),
+            Self::Array { items } => format!("array[{}]", items.short_description()),
+            Self::Object { properties, .. } => format!("object{{{}}}", properties.len()),
+            Self::Ref { name } => format!("${name}"),
+            Self::AnyOf { options } => {
+                let types: Vec<_> = options.iter().map(|o| o.short_description()).collect();
+                types.join(" | ")
+            }
+            Self::Null => "null".to_string(),
+        }
+    }
+}
