+    fn render_summary_minimal(&self, summary: &OpenApiSummary) -> String {
+        let muted = self.theme.muted.to_ansi_fg();
+        let accent = self.theme.accent.to_ansi_fg();
+        let header = self.theme.header.to_ansi_fg();
+
