+
+        if let Some(desc) = &summary.description {
+            lines.push(format!("{muted}{desc}{ANSI_RESET}"));
+        }
+
+        // Endpoints
+        lines.push(String::new());
+        lines.push(format!(
+            "{header}Endpoints{ANSI_RESET} {muted}({}){ANSI_RESET}",
