+                        format!(" {info}*{ANSI_RESET}")
+                    } else {
+                        String::new()
+                    };
+                    let type_desc = prop.schema.short_description();
+                    lines.push(format!(
+                        "{prefix}  {accent}\"{}\"{ANSI_RESET}: {muted}{type_desc}{ANSI_RESET}{required_marker}",
+                        prop.name
+                    ));
