+                lines.push(format!("{prefix}{muted}[{ANSI_RESET}"));
+                lines.push(self.render_schema_minimal(items, None, indent + 2));
+                lines.push(format!("{prefix}{muted}]{ANSI_RESET}"));
+            }
+            _ => {
+                lines.push(format!(
