+                    if let Some(desc) = &prop.description {
+                        let desc_truncated = if desc.len() > width - 6 {
+                            format!("{}...", &desc[..width - 9])
+                        } else {
+                            desc.clone()
+                        };
+                        lines.push(format!(
+                            "{border}│{ANSI_RESET}    {muted}{desc_truncated}{ANSI_RESET}"
