+                    }
+                }
+            }
+            SchemaType::Array { items } => {
+                lines.push(format!(
+                    "{border}│{ANSI_RESET}  {muted}Array of:{ANSI_RESET} {info}{}{ANSI_RESET}",
+                    items.short_description()
+                ));
+            }
